const renderClaudeFrontmatter = ({ description, argumentHint, model, allowedTools, }) => {
    const lines = ["---", `description: ${description}`];
    if (argumentHint !== undefined) {
        // JSON.stringify produces a double-quoted YAML scalar so values containing
        // `[...]` aren't parsed as flow sequences (e.g. "[all|dataset] [<key>]").
        lines.push(`argument-hint: ${JSON.stringify(argumentHint)}`);
    }
    if (model !== undefined) {
        lines.push(`model: ${model}`);
    }
    if (allowedTools !== undefined) {
        const formatted = `[${allowedTools.map((t) => JSON.stringify(t)).join(", ")}]`;
        lines.push(`allowed-tools: ${formatted}`);
    }
    lines.push("---");
    return lines.join("\n");
};
/**
 * Claude Agent Skill frontmatter (for split phase sub-skills). Unlike a Claude
 * command, a skill needs a `name:` (matching its directory). Skills are
 * model-invoked by `description`, so no `argument-hint`.
 *
 * `user-invocable: false` hides the sub-skill from the `/` menu (it's only
 * meant to be dispatched by the orchestrator) while leaving it invocable by the
 * model via the Skill tool. (`disable-model-invocation` would do the opposite,
 * and is also ignored for plugin skills per anthropics/claude-code#22345.)
 */
const renderClaudeSkillFrontmatter = ({ flowId, description, model, allowedTools, }) => {
    const lines = [
        "---",
        `name: ${flowId}`,
        `description: ${description}`,
        "user-invocable: false",
    ];
    if (model !== undefined) {
        lines.push(`model: ${model}`);
    }
    if (allowedTools !== undefined) {
        const formatted = `[${allowedTools.map((t) => JSON.stringify(t)).join(", ")}]`;
        lines.push(`allowed-tools: ${formatted}`);
    }
    lines.push("---");
    return lines.join("\n");
};
const renderCursorFrontmatter = ({ flowId, description, argumentHint, }) => {
    const usage = argumentHint !== undefined
        ? `. Usage: /bitfab-${flowId} ${argumentHint}`
        : "";
    return [
        "---",
        `name: bitfab-${flowId}`,
        `description: "${description}${usage}"`,
        "---",
    ].join("\n");
};
const renderCodexFrontmatter = ({ flowId, description, argumentHint, }) => {
    const usage = argumentHint !== undefined
        ? `. Invoke with $bitfab:${flowId} ${argumentHint}.`
        : "";
    return [
        "---",
        `name: ${flowId}`,
        `description: "${description}${usage}"`,
        "---",
    ].join("\n");
};
const renderCursorDevFrontmatter = ({ flowId, description, argumentHint, }) => {
    const usage = argumentHint !== undefined
        ? `. Usage: /bitfab-dev-${flowId} ${argumentHint}`
        : "";
    return [
        "---",
        `name: bitfab-dev-${flowId}`,
        `description: "${description}${usage}"`,
        "---",
    ].join("\n");
};
const renderCodexDevFrontmatter = ({ flowId, description, argumentHint, }) => {
    const usage = argumentHint !== undefined
        ? `. Invoke with $bitfab-dev:${flowId} ${argumentHint}.`
        : "";
    // Codex scopes a skill's handle as `<plugin-name>:<skill-name>`. The plugin is
    // named `bitfab-dev`, so the skill name is the bare flowId (e.g. `sync`),
    // yielding `bitfab-dev:sync`. Prefixing the name with `dev-` here would double
    // it to `bitfab-dev:dev-sync`. (Cursor needs the full `bitfab-dev-` prefix
    // because its skills share one flat namespace with no plugin scoping.)
    return [
        "---",
        `name: ${flowId}`,
        `description: "${description}${usage}"`,
        "---",
    ].join("\n");
};
